import os
import uuid
import pickle
import io
import hashlib
import hmac
import struct
from datetime import datetime
from typing import Dict, Any, Optional

import numpy as np
from fastapi import FastAPI, UploadFile, File, HTTPException, Form, Depends
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from pydantic import BaseModel, Field
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI(title="Multi-Tenant ML Model Serving Platform")
security = HTTPBearer()

# --- Storage ---
MODEL_STORAGE_DIR = "model_storage"
os.makedirs(MODEL_STORAGE_DIR, exist_ok=True)

# In-memory registries (use a database in production)
tenant_models: Dict[str, Dict[str, Any]] = {}
# tenant_id -> {model_id -> model_metadata}

loaded_models: Dict[str, Any] = {}
# model_id -> loaded model object

# Simple tenant API keys (use a proper auth system in production)
TENANT_API_KEYS = {
    "tenant-key-001": "tenant_alpha",
    "tenant-key-002": "tenant_beta",
    "tenant-key-003": "tenant_gamma",
}

MAX_MODEL_SIZE_BYTES = 50 * 1024 * 1024  # 50 MB
ALLOWED_MODEL_EXTENSIONS = {".pkl", ".pickle"}


# --- Safe Unpickler ---
class RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows safe classes to be deserialized.
    This prevents arbitrary code execution via malicious pickle files.
    """

    ALLOWED_MODULES_CLASSES = {
        "sklearn.linear_model._base": {"LinearRegression"},
        "sklearn.linear_model._logistic": {"LogisticRegression"},
        "sklearn.linear_model._ridge": {"Ridge", "RidgeClassifier"},
        "sklearn.linear_model._stochastic_gradient": {"SGDClassifier", "SGDRegressor"},
        "sklearn.tree._classes": {"DecisionTreeClassifier", "DecisionTreeRegressor"},
        "sklearn.ensemble._forest": {"RandomForestClassifier", "RandomForestRegressor"},
        "sklearn.ensemble._gb": {"GradientBoostingClassifier", "GradientBoostingRegressor"},
        "sklearn.ensemble._voting": {"VotingClassifier", "VotingRegressor"},
        "sklearn.svm._classes": {"SVC", "SVR", "LinearSVC", "LinearSVR"},
        "sklearn.neighbors._classification": {"KNeighborsClassifier"},
        "sklearn.neighbors._regression": {"KNeighborsRegressor"},
        "sklearn.naive_bayes": {"GaussianNB", "MultinomialNB", "BernoulliNB"},
        "sklearn.preprocessing._data": {
            "StandardScaler", "MinMaxScaler", "MaxAbsScaler",
            "RobustScaler", "Normalizer",
        },
        "sklearn.preprocessing._label": {"LabelEncoder", "LabelBinarizer"},
        "sklearn.preprocessing._encoders": {"OneHotEncoder", "OrdinalEncoder"},
        "sklearn.pipeline": {"Pipeline"},
        "sklearn.compose._column_transformer": {"ColumnTransformer"},
        "sklearn.impute._base": {"SimpleImputer"},
        "sklearn.feature_extraction.text": {"TfidfVectorizer", "CountVectorizer"},
        "sklearn.cluster._kmeans": {"KMeans"},
        "sklearn.decomposition._pca": {"PCA"},
        "numpy": {"ndarray", "dtype", "float64", "float32", "int64", "int32", "bool_"},
        "numpy.core.multiarray": {"scalar", "_reconstruct"},
        "numpy.core.numeric": {"*"},
        "builtins": {"dict", "list", "tuple", "set", "frozenset", "str", "int", "float", "bool", "bytes", "type", "slice", "complex", "range"},
        "collections": {"OrderedDict", "defaultdict"},
        "copy_reg": {"_reconstructor"},  # needed for object reconstruction
        "copyreg": {"_reconstructor"},
    }

    def find_class(self, module: str, name: str):
        if module in self.ALLOWED_MODULES_CLASSES:
            allowed = self.ALLOWED_MODULES_CLASSES[module]
            if "*" in allowed or name in allowed:
                return super().find_class(module, name)

        raise pickle.UnpicklingError(
            f"Deserialization of '{module}.{name}' is not allowed. "
            f"This class is not in the approved allowlist."
        )


def safe_pickle_load(file_bytes: bytes) -> Any:
    """Load a pickle file using the restricted unpickler."""
    return RestrictedUnpickler(io.BytesIO(file_bytes)).load()


# --- Auth ---
def get_tenant_id(credentials: HTTPAuthorizationCredentials = Depends(security)) -> str:
    token = credentials.credentials
    tenant_id = TENANT_API_KEYS.get(token)
    if tenant_id is None:
        raise HTTPException(status_code=401, detail="Invalid API key")
    return tenant_id


# --- Models ---
class ModelMetadata(BaseModel):
    model_id: str
    tenant_id: str
    model_name: str
    description: Optional[str] = ""
    uploaded_at: str
    file_size_bytes: int
    file_hash_sha256: str
    is_loaded: bool = False


class InferenceRequest(BaseModel):
    model_id: str
    input_data: Any = Field(..., description="Input data for prediction (list of lists for tabular data)")


class InferenceResponse(BaseModel):
    model_id: str
    tenant_id: str
    predictions: Any
    timestamp: str


class ModelListResponse(BaseModel):
    tenant_id: str
    models: list[ModelMetadata]


# --- Endpoints ---
@app.post("/models/upload", response_model=ModelMetadata)
async def upload_model(
    model_file: UploadFile = File(...),
    model_name: str = Form(...),
    description: str = Form(""),
    tenant_id: str = Depends(get_tenant_id),
):
    """Upload a serialized model file (pickle format)."""

    # Validate file extension
    file_ext = os.path.splitext(model_file.filename or "")[1].lower()
    if file_ext not in ALLOWED_MODEL_EXTENSIONS:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid file extension '{file_ext}'. Allowed: {ALLOWED_MODEL_EXTENSIONS}"
        )

    # Read file content
    file_content = await model_file.read()

    # Validate file size
    if len(file_content) > MAX_MODEL_SIZE_BYTES:
        raise HTTPException(
            status_code=413,
            detail=f"File too large. Maximum size: {MAX_MODEL_SIZE_BYTES / (1024*1024):.0f} MB"
        )

    if len(file_content) == 0:
        raise HTTPException(status_code=400, detail="Empty file uploaded")

    # Compute file hash for integrity
    file_hash = hashlib.sha256(file_content).hexdigest()

    # Validate the pickle file can be safely loaded
    try:
        model_obj = safe_pickle_load(file_content)
    except pickle.UnpicklingError as e:
        logger.warning(f"Tenant {tenant_id} attempted to upload model with disallowed classes: {e}")
        raise HTTPException(
            status_code=400,
            detail=f"Model file contains disallowed classes and was rejected for security reasons: {str(e)}"
        )
    except Exception as e:
        logger.warning(f"Tenant {tenant_id} uploaded invalid pickle file: {e}")
        raise HTTPException(
            status_code=400,
            detail=f"Failed to deserialize model file: {str(e)}"
        )

    # Validate the model has a predict method
    if not hasattr(model_obj, "predict"):
        raise HTTPException(
            status_code=400,
            detail="Uploaded model does not have a 'predict' method. Only scikit-learn compatible models are supported."
        )

    # Generate model ID
    model_id = f"{tenant_id}_{uuid.uuid4().hex[:12]}"

    # Save file to disk
    tenant_dir = os.path.join(MODEL_STORAGE_DIR, tenant_id)
    os.makedirs(tenant_dir, exist_ok=True)
    model_path = os.path.join(tenant_dir, f"{model_id}.pkl")

    with open(model_path, "wb") as f:
        f.write(file_content)

    # Store metadata
    metadata = ModelMetadata(
        model_id=model_id,
        tenant_id=tenant_id,
        model_name=model_name,
        description=description,
        uploaded_at=datetime.utcnow().isoformat(),
        file_size_bytes=len(file_content),
        file_hash_sha256=file_hash,
        is_loaded=True,
    )

    if tenant_id not in tenant_models:
        tenant_models[tenant_id] = {}
    tenant_models[tenant_id][model_id] = metadata

    # Cache loaded model
    loaded_models[model_id] = model_obj

    logger.info(f"Tenant '{tenant_id}' uploaded model '{model_name}' (id: {model_id}, size: {len(file_content)} bytes)")

    return metadata


@app.get("/models", response_model=ModelListResponse)
async def list_models(tenant_id: str = Depends(get_tenant_id)):
    """List all models for the authenticated tenant."""
    models = list(tenant_models.get(tenant_id, {}).values())
    return ModelListResponse(tenant_id=tenant_id, models=models)


@app.get("/models/{model_id}", response_model=ModelMetadata)
async def get_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Get metadata for a specific model."""
    tenant_model_registry = tenant_models.get(tenant_id, {})
    if model_id not in tenant_model_registry:
        raise HTTPException(status_code=404, detail="Model not found")
    return tenant_model_registry[model_id]


@app.post("/models/{model_id}/load")
async def load_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Load a previously uploaded model into memory."""
    tenant_model_registry = tenant_models.get(tenant_id, {})
    if model_id not in tenant_model_registry:
        raise HTTPException(status_code=404, detail="Model not found")

    if model_id in loaded_models:
        return {"message": "Model already loaded", "model_id": model_id}

    model_path = os.path.join(MODEL_STORAGE_DIR, tenant_id, f"{model_id}.pkl")
    if not os.path.exists(model_path):
        raise HTTPException(status_code=404, detail="Model file not found on disk")

    try:
        with open(model_path, "rb") as f:
            file_content = f.read()
        model_obj = safe_pickle_load(file_content)
    except pickle.UnpicklingError as e:
        raise HTTPException(status_code=400, detail=f"Model contains disallowed classes: {str(e)}")
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to load model: {str(e)}")

    loaded_models[model_id] = model_obj
    tenant_model_registry[model_id].is_loaded = True

    logger.info(f"Model '{model_id}' loaded for tenant '{tenant_id}'")
    return {"message": "Model loaded successfully", "model_id": model_id}


@app.post("/models/{model_id}/unload")
async def unload_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Unload a model from memory."""
    tenant_model_registry = tenant_models.get(tenant_id, {})
    if model_id not in tenant_model_registry:
        raise HTTPException(status_code=404, detail="Model not found")

    if model_id in loaded_models:
        del loaded_models[model_id]
        tenant_model_registry[model_id].is_loaded = False
        logger.info(f"Model '{model_id}' unloaded for tenant '{tenant_id}'")

    return {"message": "Model unloaded", "model_id": model_id}


@app.post("/predict", response_model=InferenceResponse)
async def predict(request: InferenceRequest, tenant_id: str = Depends(get_tenant_id)):
    """Run inference using a loaded model."""
    model_id = request.model_id

    # Verify tenant owns this model
    tenant_model_registry = tenant_models.get(tenant_id, {})
    if model_id not in tenant_model_registry:
        raise HTTPException(
            status_code=404,
            detail="Model not found. Ensure the model belongs to your tenant."
        )

    # Check model is loaded
    if model_id not in loaded_models:
        raise HTTPException(
            status_code=400,
            detail="Model is not loaded. Call POST /models/{model_id}/load first."
        )

    model = loaded_models[model_id]

    try:
        # Convert input to numpy array
        input_array = np.array(request.input_data)

        # Ensure 2D input for sklearn models
        if input_array.ndim == 1:
            input_array = input_array.reshape(1, -1)

        predictions = model.predict(input_array)

        # Convert numpy types to native Python types for JSON serialization
        if isinstance(predictions, np.ndarray):
            predictions = predictions.tolist()

    except ValueError as e:
        raise HTTPException(status_code=400, detail=f"Invalid input data format: {str(e)}")
    except Exception as e:
        logger.error(f"Inference error for model '{model_id}': {e}")
        raise HTTPException(status_code=500, detail=f"Inference failed: {str(e)}")

    logger.info(f"Tenant '{tenant_id}' ran inference on model '{model_id}'")

    return InferenceResponse(
        model_id=model_id,
        tenant_id=tenant_id,
        predictions=predictions,
        timestamp=datetime.utcnow().isoformat(),
    )


@app.delete("/models/{model_id}")
async def delete_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Delete a model (unloads from memory and removes from disk)."""
    tenant_model_registry = tenant_models.get(tenant_id, {})
    if model_id not in tenant_model_registry:
        raise HTTPException(status_code=404, detail="Model not found")

    # Unload from memory
    if model_id in loaded_models:
        del loaded_models[model_id]

    # Remove from disk
    model_path = os.path.join(MODEL_STORAGE_DIR, tenant_id, f"{model_id}.pkl")
    if os.path.exists(model_path):
        os.remove(model_path)

    # Remove metadata
    del tenant_model_registry[model_id]

    logger.info(f"Model '{model_id}' deleted for tenant '{tenant_id}'")
    return {"message": "Model deleted successfully", "model_id": model_id}


